<?php
namespace App\Modules\Hr\Analytics\Actions;use App\Modules\Hr\Analytics\Models\HrAnalyticsSnapshot;use App\Modules\Hr\Attendance\Models\HrAttendanceAnomaly;use App\Modules\Hr\Compensation\Models\HrSalaryRecord;use App\Modules\Hr\Core\Services\HrAuditService;use App\Modules\Hr\Core\Services\TenantContext;use App\Modules\Hr\Leave\Enums\LeaveRequestStatus;use App\Modules\Hr\Leave\Models\HrLeaveRequest;use App\Modules\Hr\Personnel\Models\HrEmployee;use App\Modules\Hr\Personnel\Models\HrEmploymentRecord;use App\Modules\Hr\Recruitment\Models\HrJobPosting;use App\Modules\Hr\Training\Models\HrTrainingEnrollment;use Carbon\Carbon;
class BuildHrAnalyticsSnapshotAction{public function __construct(private HrAuditService $audit){}public function execute(string $from,string $to):HrAnalyticsSnapshot{abort_unless(auth()->user()?->hasHrPermission('hr.analytics.view'),403);$tenant=app(TenantContext::class)->getId();$start=Carbon::parse($from)->startOfDay();$end=Carbon::parse($to)->endOfDay();abort_if($end->lt($start)||$start->diffInDays($end)>730,422,'Analiz dönemi geçersiz.');$headcount=HrEmployee::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->where('status','active')->count();$hires=HrEmploymentRecord::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->whereBetween('start_date',[$start,$end])->count();$exits=HrEmploymentRecord::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->whereBetween('end_date',[$start,$end])->count();$leave=(float)HrLeaveRequest::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->where('status',LeaveRequestStatus::Approved->value)->whereBetween('start_date',[$start,$end])->sum('requested_amount');$anomalies=HrAttendanceAnomaly::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->whereBetween('work_date',[$start,$end])->count();$training=HrTrainingEnrollment::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->where('status','completed')->whereBetween('completed_at',[$start,$end])->count();$openRoles=HrJobPosting::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->where('status','published')->sum('headcount');$salaryCost=null;if(auth()->user()?->hasHrPermission('hr.salary.view')){$salaryCost=HrSalaryRecord::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->where('status','approved')->get()->sum(fn($r)=>$r->grossSalary());}$metrics=['headcount'=>$headcount,'hires'=>$hires,'exits'=>$exits,'turnover_rate'=>$headcount>0?round($exits/$headcount*100,1):0,'approved_leave_units'=>$leave,'attendance_anomalies'=>$anomalies,'training_completions'=>$training,'open_headcount'=>$openRoles,'monthly_gross_cost'=>$salaryCost];$sources=['headcount'=>'hr_employees.status','hires_exits'=>'hr_employment_records.start_date/end_date','leave'=>'hr_leave_requests.requested_amount (approved)','attendance'=>'hr_attendance_anomalies.work_date','training'=>'hr_training_enrollments.completed_at','recruitment'=>'hr_job_postings.headcount (published)','salary'=>$salaryCost===null?'hidden: hr.salary.view required':'hr_salary_records latest approved'];$hash=hash('sha256',json_encode([$tenant,$from,$to,$metrics,$sources]));$snapshot=HrAnalyticsSnapshot::create(['legal_entity_id'=>$tenant,'period_start'=>$start,'period_end'=>$end,'metrics'=>$metrics,'sources'=>$sources,'source_hash'=>$hash,'generated_by'=>auth()->id(),'generated_at'=>now()]);$this->audit->log('hr_analytics_snapshot_generated',$snapshot,null,['source_hash'=>$hash]);return $snapshot;}}
